ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?building ?area WHERE {
  ?rooms a :Rooms .
  ?rooms p:Building ?building .
  ?rooms p:Area ?area .
  ?rooms p:Spa ?spa_f .
  ?rooms p:Rate ?rate_o .
  FILTER((STR(?spa_f) = "1" || STR(?spa_f) = "1.0"))
}
ORDER BY ASC(?rate_o)
LIMIT 1 }
  component: { SELECT ?area WHERE {
  ?rooms a :Rooms .
  ?rooms p:Area ?area .
  ?rooms p:Spa ?spa_f .
  ?rooms p:Rate ?rate_o .
  FILTER((STR(?spa_f) = "1" || STR(?spa_f) = "1.0"))
}
ORDER BY ASC(?rate_o)
LIMIT 1 }
  component_2: { SELECT ?building WHERE {
  ?rooms a :Rooms .
  ?rooms p:Building ?building .
  ?rooms p:Spa ?spa_f .
  ?rooms p:Rate ?rate_o .
  FILTER((STR(?spa_f) = "1" || STR(?spa_f) = "1.0"))
}
ORDER BY ASC(?rate_o)
LIMIT 1 }
}

